* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: #030a03; font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; color: white; padding: 20px; }
.game { display: flex; flex-direction: column; align-items: center; gap: 16px; }
.header { display: flex; justify-content: space-between; align-items: center; width: 400px; }
h1 { font-size: 28px; font-weight: 900; }
.scores { display: flex; gap: 12px; }
.score-box { background: rgba(255,255,255,0.07); border-radius: 10px; padding: 8px 16px; text-align: center; } .score-box span { display: block; font-size: 11px; color: rgba(255,255,255,0.5); } .score-box strong { font-size: 20px; font-weight: 800; }
#canvas { border-radius: 16px; border: 2px solid rgba(34,197,94,0.3); box-shadow: 0 0 30px rgba(34,197,94,0.1); }
.overlay { position: absolute; width: 400px; height: 400px; background: rgba(3,10,3,0.85); border-radius: 16px; display: flex; align-items: center; justify-content: center; backdrop-filter: blur(8px); }
.overlay-content { text-align: center; }
.overlay-emoji { font-size: 56px; margin-bottom: 16px; }
.overlay-content h2 { font-size: 28px; font-weight: 800; margin-bottom: 8px; }
.overlay-content p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 24px; }
.overlay-content button { padding: 14px 36px; border-radius: 14px; border: none; background: #22c55e; color: white; font-size: 16px; font-weight: 800; cursor: pointer; }
.controls { display: flex; flex-direction: column; gap: 6px; align-items: center; }
.ctrl-row { display: flex; gap: 6px; }
.ctrl-row button { width: 52px; height: 52px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.12); background: rgba(255,255,255,0.07); color: white; font-size: 18px; cursor: pointer; transition: background 0.15s; } .ctrl-row button:active { background: rgba(34,197,94,0.3); }

