const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d');
const GRID = 20, SIZE = 400/GRID;
let snake, food, direction, nextDir, score, best = 0, running = false, interval;
function startGame() {
  snake = [{x:10,y:10},{x:9,y:10},{x:8,y:10}];
  direction = 'RIGHT'; nextDir = 'RIGHT';
  score = 0; running = true;
  document.getElementById('score').textContent = 0;
  document.getElementById('overlay').style.display = 'none';
  placeFood();
  clearInterval(interval);
  interval = setInterval(loop, 120);
}
function placeFood() {
  do { food = {x: Math.floor(Math.random()*GRID), y: Math.floor(Math.random()*GRID)}; }
  while (snake.some(s => s.x===food.x && s.y===food.y));
}
function dir(d) {
  const opp = {UP:'DOWN',DOWN:'UP',LEFT:'RIGHT',RIGHT:'LEFT'};
  if (d !== opp[direction]) nextDir = d;
}
function loop() {
  direction = nextDir;
  const head = {...snake[0]};
  if (direction==='UP') head.y--;
  else if (direction==='DOWN') head.y++;
  else if (direction==='LEFT') head.x--;
  else if (direction==='RIGHT') head.x++;
  if (head.x<0||head.x>=GRID||head.y<0||head.y>=GRID||snake.some(s=>s.x===head.x&&s.y===head.y)) {
    clearInterval(interval); running = false;
    if (score > best) { best = score; document.getElementById('best').textContent = best; }
    document.getElementById('overlay-emoji').textContent = '💀';
    document.getElementById('overlay-title').textContent = 'Oyun Bitti!';
    document.getElementById('overlay-msg').textContent = 'Puanın: ' + score;
    document.getElementById('overlay').style.display = 'flex';
    return;
  }
  snake.unshift(head);
  if (head.x===food.x && head.y===food.y) { score++; document.getElementById('score').textContent = score; placeFood(); }
  else snake.pop();
  draw();
}
function draw() {
  ctx.fillStyle = '#030a03';
  ctx.fillRect(0,0,400,400);
  for (let i=0;i<GRID;i++) for (let j=0;j<GRID;j++) {
    if ((i+j)%2===0) { ctx.fillStyle='rgba(255,255,255,0.02)'; ctx.fillRect(i*SIZE,j*SIZE,SIZE,SIZE); }
  }
  snake.forEach((s,i) => {
    const g = ctx.createRadialGradient(s.x*SIZE+SIZE/2,s.y*SIZE+SIZE/2,1,s.x*SIZE+SIZE/2,s.y*SIZE+SIZE/2,SIZE/2);
    g.addColorStop(0, i===0?'#86efac':'#22c55e');
    g.addColorStop(1, i===0?'#22c55e':'#15803d');
    ctx.fillStyle = g;
    ctx.beginPath();
    ctx.roundRect(s.x*SIZE+1,s.y*SIZE+1,SIZE-2,SIZE-2,4);
    ctx.fill();
  });
  const fg = ctx.createRadialGradient(food.x*SIZE+SIZE/2,food.y*SIZE+SIZE/2,1,food.x*SIZE+SIZE/2,food.y*SIZE+SIZE/2,SIZE/2);
  fg.addColorStop(0,'#fca5a5'); fg.addColorStop(1,'#ef4444');
  ctx.fillStyle = fg;
  ctx.beginPath();
  ctx.arc(food.x*SIZE+SIZE/2,food.y*SIZE+SIZE/2,SIZE/2-2,0,Math.PI*2);
  ctx.fill();
}
document.addEventListener('keydown', e => {
  const map = {ArrowUp:'UP',ArrowDown:'DOWN',ArrowLeft:'LEFT',ArrowRight:'RIGHT',w:'UP',s:'DOWN',a:'LEFT',d:'RIGHT'};
  if (map[e.key]) { e.preventDefault(); dir(map[e.key]); }
  if (!running && (map[e.key] || e.key===' ')) startGame();
});
